import { computed, inject, Injectable, Signal } from '@angular/core';
import { toSignal } from '@angular/core/rxjs-interop';
import { ActivatedRoute, Router } from '@angular/router';
import { Category, CategoryGroup, CategoryGroupWithPillColor } from '@core/models/category.model';
import { Store } from '@ngxs/store';
import { CategorySelectors } from '@store/category/category.selectors';
import { CategoryState } from '@store/category/category.state';
import { DropdownOption } from '@ui/form/dropdown/dropdown';
import { getPillColor } from '@ui/pill/pill-color';
import { map } from 'rxjs';

interface CategoryQueryParams {
  search: string | null;
  group: number | null;
}

@Injectable({
  providedIn: 'root',
})
export class CategoryPageService {
  readonly #store = inject(Store);
  readonly #route = inject(ActivatedRoute);
  readonly #router = inject(Router);

  readonly #categories: Signal<Category[]> = this.#store.selectSignal(
    CategorySelectors.visibleCategories,
  );
  readonly #categoriesGroup: Signal<CategoryGroup[]> = this.#store.selectSignal(
    CategorySelectors.categoryGroups,
  );
  readonly isLoading = this.#store.selectSignal(CategorySelectors.isLoading);
  readonly error = this.#store.selectSignal(CategorySelectors.error);


  readonly #queryParams = toSignal(
    this.#route.queryParamMap.pipe(
      map((params) => {
        return {
          search: params.get('search'),
          group: params.get('group') ? Number(params.get('group')) : null,
        };
      }),
    ),
  );

  public addFiltersToQueryParams(search: string | null | undefined, group: number | null): void {
    this.#router.navigate([], {
      relativeTo: this.#route,
      queryParams: {
        search,
        group,
      },
      queryParamsHandling: 'merge',
    });
  }

  public getCategoriesByAlphabet = computed(() => {
    const categories: Category[] = this.#categories();
    const queryParams = this.#queryParams();
    categories.sort((a: Category, b: Category) => a.wording.localeCompare(b.wording));

    let sortedCategories = [...categories].sort((a, b) => a.wording.localeCompare(b.wording));

    return this.#filterCategoriesByQueryParams(sortedCategories, queryParams);
  });

  public getCategoriesGrouped = computed(() => {
    let categories: Category[] = this.#categories();
    const queryParams = this.#queryParams();
    const categoriesByGroup = new Map<CategoryGroupWithPillColor, Category[]>();

    let filteredCategories = this.#filterCategoriesByQueryParams(categories, queryParams);

    filteredCategories.forEach((category: Category) => {
      const currentGroupId = category.group?.id ?? 0;
      let groupKey = Array.from(categoriesByGroup.keys()).find((k) => k.id === currentGroupId);

      if (!groupKey) {
        groupKey = category.group
          ? { ...category.group, pillColor: getPillColor(category.group.color) }
          : { id: 0, name: 'Sans groupe', color: '', pillColor: getPillColor('') };

        categoriesByGroup.set(groupKey, []);
      }

      categoriesByGroup.get(groupKey)!.push(category);
    });

    return categoriesByGroup;
  });

  public dropdownOptions: Signal<DropdownOption[]> = computed(() => {
    const categoriesGroup = this.#categoriesGroup();
    if (!categoriesGroup) return [];

    const options = categoriesGroup
      .map((group: CategoryGroup) => {
        return {
          value: group.id.toString(),
          label: group.name,
        } as DropdownOption;
      })
      .sort((a: DropdownOption, b: DropdownOption) => a.label.localeCompare(b.label));

    options.unshift({ value: '', label: 'Tous les groupes de catégories' } as DropdownOption);
    return options;
  });

  #filterCategoriesByQueryParams(
    categories: Category[],
    queryParams: CategoryQueryParams | undefined,
  ): Category[] {
    if (!queryParams) return categories;
    let filteredCategories = categories;

    if (queryParams.group) {
      filteredCategories = this.#filterCategoriesByGroup(filteredCategories, queryParams.group);
    }

    if (queryParams.search) {
      filteredCategories = this.#filterCategoriesBySearch(filteredCategories, queryParams.search);
    }

    return filteredCategories;
  }

  #filterCategoriesByGroup(categories: Category[], groupId: number): Category[] {
    return categories.filter((category) => category.group?.id === groupId);
  }

  #filterCategoriesBySearch(categories: Category[], search: string): Category[] {
  if (!search || search.trim() === '') return categories;

  const searchTerms = search.toLowerCase().trim().split(/\s+/);

  return categories.filter(category => {
    const wordingWords = category.wording.toLocaleLowerCase().trim().split(/[\s-']/);
    return searchTerms.every(searchTerm => {
      return wordingWords.some(word => word.startsWith(searchTerm));

    });
  });
}
}

import { Injectable, inject } from '@angular/core';
import { Action, State, StateContext } from '@ngxs/store';
import { catchError, tap } from 'rxjs/operators';
import { Category, CategoryGroup } from '@core/models/category.model';
import { CategoryService } from '@core/services/category.webservice';
import { FetchCategoriesData } from '@store/category/category.actions';
import { forkJoin, of } from 'rxjs';

export interface CategoryStateModel {
  allCategories: Category[];
  visibleCategories: Category[];
  isLoading: boolean;
  error: string | null;
}

@State<CategoryStateModel>({
  name: 'categories',
  defaults: {
    allCategories: [],
    visibleCategories: [],
    isLoading: false,
    error: null,
  },
})
@Injectable()
export class CategoryState {
  private readonly categoryService = inject(CategoryService);

  @Action(FetchCategoriesData)
  fetchAllCategoriesAndGroups(ctx: StateContext<CategoryStateModel>) {
    ctx.patchState({ isLoading: true, error: null });

    return forkJoin({
      all: this.categoryService.getAllCategories(),
      visible: this.categoryService.getVisibleCategories(),
    }).pipe(
      tap(({ all, visible }) => {
        const visibleCategories: Category[] = all.filter((category) =>
          visible.some((vc) => vc.id === category.id),
        );
        ctx.patchState({
          allCategories: all,
          visibleCategories,
          isLoading: false,
        });
      }),
      catchError(() => {
        ctx.patchState({ isLoading: false, error: 'Erreur lors du chargement des catégories' });
       return of(null)
      }),
    );
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  ElementRef,
  forwardRef,
  HostListener,
  input,
  model,
  signal,
  inject,
} from '@angular/core';
import { ControlValueAccessor, NG_VALUE_ACCESSOR } from '@angular/forms';
import { IconComponent } from '@ui/icon/icon';

export interface DropdownOption<T = string> {
  value: T;
  label: string;
}

@Component({
  selector: 'app-dropdown',
  imports: [IconComponent],
  template: `
    <div
      class="dropdown__wrapper"
      [class.dropdown__wrapper--disabled]="disabled()"
      [class.dropdown__wrapper--opened]="isOpen()"
      (click)="toggleDropdown()"
    >
      <div class="dropdown__control paragraph-tiny">
        {{ selectedOption()?.label || placeholder() }}
      </div>
      <app-icon name="arrow" class="dropdown__icon" aria-hidden="true"></app-icon>
      @if (isOpen()) {
        <ul class="dropdown__options-list">
          @for (option of options(); track option.value) {
            <li
              class="dropdown__option paragraph-tiny"
              [class.dropdown__option--selected]="value() === option.value"
              (click)="selectOption(option)"
            >
              {{ option.label }}
            </li>
          }
        </ul>
      }
    </div>
  `,
  styles: `
    .dropdown {
      &__wrapper {
        position: relative;
        display: flex;
        align-items: center;
        width: 100%;
        border: 0.0625rem solid var(--separator, #e0e0e0);
        border-radius: 0.25rem;
        background-color: var(--background, #ffffff);
        transition:
          border-color 0.2s ease,
          box-shadow 0.2s ease;
        cursor: pointer;
        height: 100%;

        &--disabled {
          opacity: 0.5;
          cursor: not-allowed;
          pointer-events: none;
        }

        &--opened {
          border-color: var(--cerulean);

          .dropdown__icon {
            color: var(--cerulean);
            transform: rotate(180deg);
          }
        }
      }

      &__icon {
        flex-shrink: 0;
        color: var(--text-color, inherit);
        transition:
          transform 0.2s ease,
          color 0.2s ease;
        display: flex;
        align-items: center;
        justify-content: center;
        padding: 0 0.5625rem 0 0;
      }

      &__control {
        flex: 1 1 auto;
        width: 100%;
        min-width: 0;
        border: none;
        outline: none;
        background: transparent;
        padding: 0.5938rem 0 0.5938rem 0.5625rem;
      }

      &__options-list {
        position: absolute;
        top: calc(100% + 0.25rem);
        left: 0;
        right: 0;
        background-color: var(--background, #ffffff);
        border: 1px solid var(--separator);
        border-radius: 0.25rem;
        list-style: none;
        padding: 0.25rem 0;
        margin: 0;
        z-index: 10;
        max-height: 12.5rem;
        overflow-y: auto;
      }

      &__option {
        padding: 0.5rem 0.75rem;
        cursor: pointer;
        transition: background-color 0.2s ease;

        &:hover {
          background-color: #f5f5f5;
          font-weight: 500;
        }

        &--selected {
          color: var(--cerulean);
          font-weight: 600;

          &:hover {
            font-weight: 600;
          }
        }
      }
    }
  `,
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: forwardRef(() => DropdownComponent),
      multi: true,
    },
  ],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class DropdownComponent<T> implements ControlValueAccessor {
  private readonly elementRef = inject(ElementRef);

  readonly placeholder = input<string>('');
  readonly options = input<DropdownOption<T>[]>([]);
  readonly ariaLabel = input<string>();
  readonly disabled = model<boolean>(false);

  readonly value = signal<T | null | undefined>(undefined);
  readonly isOpen = signal(false);

  readonly selectedOption = computed(() => this.options().find((o) => o.value === this.value()));

  readonly id = 'dropdown-' + Math.random().toString(9);

  // eslint-disable-next-line @typescript-eslint/no-empty-function
  onChange: (value: T) => void = () => {};
  // eslint-disable-next-line @typescript-eslint/no-empty-function
  onTouched: () => void = () => {};

  @HostListener('document:click', ['$event'])
  onDocumentClick(event: MouseEvent): void {
    if (this.isOpen() && !this.elementRef.nativeElement.contains(event.target as Node)) {
      this.isOpen.set(false);
    }
  }

  toggleDropdown(): void {
    if (!this.disabled()) {
      this.isOpen.set(!this.isOpen());
    }
  }

  selectOption(option: DropdownOption<T>): void {
    this.value.set(option.value);
    this.onChange(option.value);
    this.isOpen.set(false);
  }

  writeValue(val: T): void {
    this.value.set(val);
  }

  registerOnChange(fn: (value: T) => void): void {
    this.onChange = fn;
  }

  registerOnTouched(fn: () => void): void {
    this.onTouched = fn;
  }

  setDisabledState(isDisabled: boolean): void {
    this.disabled.set(isDisabled);
  }
}

