      <!-- Affichage des erreurs -->
      @if (error) {
        <p class="paragraph-small" style="color: red;">{{ error }}</p>
      }

      <!-- Loading skeleton -->
      @if (isLoading) {
        <ul class="category-page__skeleton">
          @for (category of skeletonArray; track category) {
            <li>
              <div class="category-page__skeleton__card"></div>
            </li>
          }
        </ul>
      }



      <!-- Vue alphabetique -->
      @if (sortType() === 'alpha' && !isLoading) {
        @if (categoriesAlphabetically.length === 0) {
          <p class="paragraph-small">Aucune catégorie trouvée</p>
        }
        <ul class="category-page__categories">
          @for (category of categoriesAlphabetically; track category) {
            <li>
              <app-card
                [title]="category.wording"
                [description]="category.description"
                [tag]="category.group?.name"
                [tagColor]="category.group?.color"
              ></app-card>
            </li>
          }
        </ul>
      }

      <!-- Vue par groupe -->
      @if (sortType() === 'grouped' && !isLoading) {
        @if (categoriesGrouped.size === 0) {
          <p class="paragraph-small">Aucune catégorie trouvée</p>
        }
        <ul class="category-page__category-groups">
          @for (group of categoriesGrouped; track group[0]) {
            @if (group[0].id) {
              <li>
                <app-subnav [color]="group[0].pillColor">{{ group[0].name }}</app-subnav>
              </li>
            }
            <ul class="category-page__categories">
              @for (category of group[1]; track category.id) {
                <li>
                  <app-card
                    [title]="category.wording"
                    [description]="category.description"
                  ></app-card>
                </li>
              }
            </ul>
          }
        </ul>
      }
    </section>

    <footer class="footer">
      <button type="button">Click there</button>
    </footer>
